import React, { forwardRef } from 'react';
import { Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  ArcElement,
  Tooltip,
  Legend
} from 'chart.js';
import ChartDataLabels from 'chartjs-plugin-datalabels';

ChartJS.register(
  ArcElement,
  Tooltip,
  Legend,
  ChartDataLabels
);

const DataInsightsPieChart = forwardRef(({ data }, ref) => {
  if (!Array.isArray(data) || data.length === 0) return null;

  const keys = Object.keys(data[0]);
  const labelKey = keys.find((k) => typeof data[0][k] === 'string');
  const valueKey = keys.find((k) => typeof data[0][k] === 'number');

  if (!labelKey || !valueKey) return null;

  const grouped = {};
  data.forEach((item) => {
    const label = item[labelKey];
    const value = Number(item[valueKey]) || 0;
    grouped[label] = (grouped[label] || 0) + value;
  });

  const labels = Object.keys(grouped);
  const values = Object.values(grouped).map((v) => Number(v.toFixed(2)));

  const shouldShowPercentage = /percent|percentage|pct|rate|ratio|share/i.test(valueKey);

  const formatValue = (value) => {
    const num = Number(value) || 0;
    return shouldShowPercentage ? `${num.toFixed(2)}%` : num.toFixed(2);
  };

  const chartData = {
    labels,
    datasets: [
      {
        data: values,
        backgroundColor: [
          '#6366F1',
          '#22C55E',
          '#F97316',
          '#EF4444',
          '#14B8A6',
          '#0EA5E9',
          '#A855F7',
          '#10B981',
          '#F59E0B',
          '#3B82F6',
          '#8B5CF6',
          '#EC4899'
        ],
        borderColor: '#ffffff',
        borderWidth: 2
      }
    ]
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    cutout: '60%',
    plugins: {
      legend: {
        position: 'top',
        labels: {
          boxWidth: 14,
          padding: 12,
          font: {
            size: 12,
            weight: '500'
          }
        }
      },
      tooltip: {
        backgroundColor: '#1f2937',
        padding: 10,
        cornerRadius: 6,
        callbacks: {
          label: (ctx) => `${ctx.label}: ${formatValue(ctx.raw)}`
        }
      },
      datalabels: {
        color: '#ffffff',
        font: {
          size: 12,
          weight: 'bold'
        },
        formatter: (value) => formatValue(value)
      }
    }
  };

  return <Pie ref={ref} data={chartData} options={options} />;
});

export default DataInsightsPieChart;
